        # Filter for strict Sports winners
        if 'Sports' in winners and len(winners) == 1:
            candidates.append({
                'title': art['title'],
                'description': art['description'],
                'len': len(art['description']),
                'scores': scores
            })

# Sort by length
candidates.sort(key=lambda x: x['len'], reverse=True)

